import sys, heapq, re

# Faithful replica of sim.c simulation semantics.

def parse(lines):
    gates = {}
    num_signals = 0
    deps = {}
    def add_dep(src, dst):
        deps.setdefault(src, []).append(dst)
    for line in lines:
        m = re.match(r'out(\d+)\s*=\s*(.+)', line)
        if not m:
            continue
        out_idx = int(m.group(1))
        op = m.group(2).strip()
        if out_idx + 1 > num_signals:
            num_signals = out_idx + 1
        if op == '0':
            gates[out_idx] = ('C0', 0, 0)
        elif op == '1':
            gates[out_idx] = ('C1', 0, 0)
        elif op.startswith('out') and ' ' not in op:
            src = int(op[3:])
            gates[out_idx] = ('COPY', src, 0)
            add_dep(src, out_idx)
        elif op.startswith('~out'):
            src = int(op[4:])
            gates[out_idx] = ('NOT', src, 0)
            add_dep(src, out_idx)
        else:
            mm = re.match(r'out(\d+)\s*(.)\s*out(\d+)', op)
            if mm:
                s1 = int(mm.group(1)); oc = mm.group(2); s2 = int(mm.group(3))
                t = {'&':'AND','|':'OR','^':'XOR'}[oc]
                gates[out_idx] = (t, s1, s2)
                add_dep(s1, out_idx); add_dep(s2, out_idx)
    return gates, num_signals, deps

def simulate(lines, input_value, steps=32000):
    gates, num_signals, deps = parse(lines)
    N = num_signals
    values = [0]*N
    def get_deps(s):
        return deps.get(s, [])
    # set inputs
    for i in range(min(32, N)):
        values[i] = (input_value >> i) & 1

    def compute(sig):
        t, s1, s2 = gates.get(sig, ('C0',0,0))
        if t=='C0': return 0
        if t=='C1': return 1
        if t=='COPY': return values[s1]
        if t=='NOT': return 0 if values[s1] else 1
        if t=='AND': return values[s1] & values[s2]
        if t=='OR': return values[s1] | values[s2]
        if t=='XOR': return values[s1] ^ values[s2]
        return 0

    next_queue = []
    next_in_queue = [False]*N
    for step in range(steps):
        if step == 0:
            cur = list(range(N))
            heapq.heapify(cur)
        else:
            cur = next_queue
            heapq.heapify(cur)
        next_queue = []
        next_in_queue = [False]*N
        did = [False]*N
        while cur:
            sig = heapq.heappop(cur)
            if did[sig]:
                continue
            did[sig] = True
            old = values[sig]
            new = compute(sig)
            if new != old:
                values[sig] = new
                for dep in get_deps(sig):
                    if not did[dep] and dep > sig:
                        heapq.heappush(cur, dep)
                    if not next_in_queue[dep]:
                        heapq.heappush(next_queue, dep)
                        next_in_queue[dep] = True
    return values, N

def output(values, N):
    r = 0
    for i in range(32):
        if values[N-32+i]:
            r |= (1<<i)
    return r

