def simulate(lines, input_value, steps=32000):
    gates, num_signals, deps = parse(lines)
    N = num_signals
    values = [0]*N
    for i in range(min(32, N)):
        values[i] = (input_value >> i) & 1
    def compute(sig):
        t, s1, s2 = gates.get(sig, ('C0',0,0))
        if t=='C0': return 0
        if t=='C1': return 1
        if t=='COPY': return values[s1]
        if t=='NOT': return 0 if values[s1] else 1
        if t=='AND': return values[s1] & values[s2]
        if t=='OR': return values[s1] | values[s2]
        if t=='XOR': return values[s1] ^ values[s2]
        return 0
    next_queue = []
    for step in range(steps):
        if step == 0:
            cur = list(range(N))
        else:
            cur = next_queue
        heapq.heapify(cur)
        next_queue = []
        next_in_queue = [False]*N
        did = [False]*N
        while cur:
            sig = heapq.heappop(cur)
            if did[sig]:
                continue
            did[sig] = True
            old = values[sig]
            new = compute(sig)
            if new != old:
                values[sig] = new
                for dep in deps.get(sig, []):
                    if not did[dep] and dep > sig:
                        heapq.heappush(cur, dep)
                    if not next_in_queue[dep]:
                        heapq.heappush(next_queue, dep)
                        next_in_queue[dep] = True
    return values, N

def output(values, N):
    r = 0
    for i in range(32):
        if values[N-32+i]:
            r |= (1<<i)
    return r
